"""Ingest HackerOne program scopes from the public bounty-targets-data feed.

No HackerOne authentication needed: the arkadiyt/bounty-targets-data repository
publishes hourly structured dumps of every program's scope. We pull a program's
in-scope assets and extract the GitHub repositories we can actually scan.
"""

from __future__ import annotations

import json
import re
import urllib.request
from dataclasses import dataclass, field

DEFAULT_FEED_URL = (
    "https://raw.githubusercontent.com/arkadiyt/bounty-targets-data/main/data/hackerone_data.json"
)

_GH_RE = re.compile(
    r"github\.com[/:]([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+?)(?:\.git)?(?:/|$|#|\?)"
)


class ScopeFeedError(RuntimeError):
    pass


@dataclass
class ProgramScope:
    handle: str
    name: str
    github_repos: list = field(default_factory=list)
    in_scope_assets: list = field(default_factory=list)
    out_of_scope_assets: list = field(default_factory=list)


def find_program(data, handle):
    handle_low = str(handle).lower()
    for program in data:
        if str(program.get("handle", "")).lower() == handle_low:
            return program
    return None


def extract_github_repos(program) -> list:
    """Owner/name GitHub repos from a program's in-scope assets (deduped)."""
    repos, seen = [], set()
    targets = (program or {}).get("targets", {}) or {}
    for asset in targets.get("in_scope") or []:
        identifier = str(asset.get("asset_identifier", ""))
        match = _GH_RE.search(identifier)
        if not match:
            continue
        repo = match.group(1)
        if repo.endswith(".git"):
            repo = repo[:-4]
        if repo.count("/") == 1 and repo not in seen:
            seen.add(repo)
            repos.append(repo)
    return repos


def parse_scope(data, handle) -> ProgramScope:
    program = find_program(data, handle)
    if program is None:
        raise ScopeFeedError(f"program '{handle}' not found in feed")
    targets = program.get("targets", {}) or {}
    return ProgramScope(
        handle=program.get("handle", handle),
        name=program.get("name", handle),
        github_repos=extract_github_repos(program),
        in_scope_assets=[a.get("asset_identifier", "") for a in (targets.get("in_scope") or [])],
        out_of_scope_assets=[
            a.get("asset_identifier", "") for a in (targets.get("out_of_scope") or [])
        ],
    )


def fetch_scope(handle, *, url=DEFAULT_FEED_URL) -> ProgramScope:
    try:
        request = urllib.request.Request(url, headers={"User-Agent": "bbscan"})
        with urllib.request.urlopen(request, timeout=60) as resp:
            data = json.loads(resp.read().decode("utf-8"))
    except ScopeFeedError:
        raise
    except Exception as exc:  # network / JSON errors
        raise ScopeFeedError(f"failed to fetch scope feed: {exc}") from exc
    return parse_scope(data, handle)

"""PY-SEC-001 — Hardcoded credential.

Flags a secret-named assignment or keyword argument whose value is a *string
literal* with real entropy. Environment reads, name references, f-strings,
placeholders, low-entropy identifier strings, and test-fixture names are all
suppressed. Favors precision: a weak all-lowercase "secret" is intentionally
not flagged to avoid flagging parameter/field names.
"""

from __future__ import annotations

import ast
import re
from collections.abc import Iterator

from scanner.context import FileContext
from scanner.models import Confidence, Finding
from scanner.rules import register
from scanner.rules.base import Rule
from scanner.suppression import (
    is_placeholder,
    looks_high_entropy,
    name_is_test_fixture,
    value_is_literal_secret,
)

_SECRET_NAME_RE = re.compile(
    r"(api[_-]?key|secret|passwd|password|token|private[_-]?key|access[_-]?key)",
    re.IGNORECASE,
)


@register
class HardcodedSecretRule(Rule):
    id = "PY-SEC-001"
    name = "Hardcoded credential"
    cvss_vector = "CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:N/A:N"
    confidence = Confidence.PROBABLE
    cwe = "CWE-798"
    remediation = (
        "Load secrets from environment variables or a secrets manager; never "
        "commit credential literals to source control."
    )
    references = ("https://cwe.mitre.org/data/definitions/798.html",)

    def analyze(self, ctx: FileContext) -> Iterator[Finding]:
        for node in ast.walk(ctx.tree):
            if isinstance(node, ast.Assign):
                name = self._single_target_name(node)
                if name and _SECRET_NAME_RE.search(name) and not name_is_test_fixture(name):
                    yield from self._check(ctx, node.value, name)
            elif isinstance(node, ast.Call):
                for kw in node.keywords:
                    if (
                        kw.arg
                        and _SECRET_NAME_RE.search(kw.arg)
                        and not name_is_test_fixture(kw.arg)
                    ):
                        yield from self._check(ctx, kw.value, kw.arg)

    def _check(self, ctx: FileContext, value_node: ast.AST, name: str) -> Iterator[Finding]:
        literal = value_is_literal_secret(value_node)
        if literal is None:
            return  # env read / name ref / f-string -> not a hardcoded literal
        if is_placeholder(literal.value):
            return
        confidence = (
            Confidence.CONFIRMED if looks_high_entropy(literal.value) else Confidence.PROBABLE
        )
        yield self.finding(
            ctx,
            literal,
            message=(
                f"Hardcoded secret assigned to `{name}`: the value is a string "
                f"literal, not a read from an environment variable or secrets manager."
            ),
            confidence=confidence,
        )

    @staticmethod
    def _single_target_name(node: ast.Assign):
        if len(node.targets) == 1 and isinstance(node.targets[0], ast.Name):
            return node.targets[0].id
        return None

"""FileContext: parse a Python file once and share the AST across all rules.

Using the AST is itself the first false-positive defense: comments do not exist
in the tree and string literals are inert ``ast.Constant`` nodes, so a token
like ``verify=False`` inside a comment or string can never be seen as a keyword
argument. A file that fails to parse (Python 2, a template, vendored junk)
yields ``None`` and is skipped rather than crashing the run.
"""

from __future__ import annotations

import ast
from dataclasses import dataclass, field
from pathlib import Path
from typing import Optional


@dataclass
class FileContext:
    path: Path
    source: str
    tree: ast.AST
    display_path: str = ""
    _lines: Optional[list] = field(default=None, repr=False)

    @classmethod
    def from_source(cls, source: str, filename: str = "<memory>") -> "Optional[FileContext]":
        try:
            tree = ast.parse(source, filename=filename)
        except (SyntaxError, ValueError):
            return None
        cls._link_parents(tree)
        return cls(path=Path(filename), source=source, tree=tree, display_path=filename)

    @classmethod
    def from_path(cls, path: Path) -> "Optional[FileContext]":
        try:
            source = Path(path).read_text(encoding="utf-8")
        except (UnicodeDecodeError, OSError):
            return None
        ctx = cls.from_source(source, str(path))
        if ctx is not None:
            ctx.path = Path(path)
        return ctx

    @property
    def lines(self) -> list:
        if self._lines is None:
            self._lines = self.source.splitlines()
        return self._lines

    def segment(self, node: ast.AST) -> str:
        seg = ast.get_source_segment(self.source, node)
        if seg is not None:
            return seg
        line_no = getattr(node, "lineno", None)
        if line_no and 1 <= line_no <= len(self.lines):
            return self.lines[line_no - 1].strip()
        return ""

    @staticmethod
    def _link_parents(tree: ast.AST) -> None:
        """Attach a ``.parent`` pointer to every node (stdlib AST lacks them)."""
        for parent in ast.walk(tree):
            for child in ast.iter_child_nodes(parent):
                child.parent = parent  # type: ignore[attr-defined]

